import React

class MemoizedComponent(React.Component):
    def __init__(self, props):
        self.props = props
        self.state = {
            'array': [],
            'renderFunction': None
        }

    def useMemo(self):
        return self.props['array']

    def useCallback(self):
        return self.renderComponent

    def renderComponent(self):
        return React.createElement('div', {}, self.props['array'].map((object, index) =>
            React.createElement('p', {}, object['id']) +
            React.createElement('ul', {}, object['children'].map((child, index) =>
                React.createElement('li', {}, child)
            ))
        ))

    def shouldComponentUpdate(self, nextProps, nextState):
        return nextProps['array'] != self.props['array'] or nextState['renderFunction'] != self.state['renderFunction']

    def render(self):
        return self.renderComponent()
